#include <stdio.h>
#include <stdlib.h>
#include <string.h>
void wordBreak(char * s, char ** wordDict, int wordDictSize) {
    int len = strlen(s);
    int *dp = (int *)malloc((len + 1) * sizeof(int));
    dp[0] = 1;
    for (int i = 1; i <= len; i++) {
        for (int j = 0; j < i; j++) {
            if (dp[j] && isValid(s + j, i - j, wordDict, wordDictSize)) {
                dp[i] = 1;
                break;
            }
        }
    }
    if (dp[len]) {
        printf("\n");
    }
    free(dp);
}
int isValid(char * s, int len, char ** wordDict, int wordDictSize) {
    for (int i = 0; i < wordDictSize; i++) {
        if (strncmp(s, wordDict[i], len) == 0 && strlen(wordDict[i]) == len) {
            return 1;
        }
    }
    return 0;
}

