code.Java:
import java.util.*;
public class Solution {
    public List<String> wordBreak(String s, List<String> wordDict) {
        Set<String> dict = new HashSet<>(wordDict);
        List<String> result = new ArrayList<>();
        backtrack(result, new ArrayList<>(), s, dict, 0);
        return result;
    }
    private void backtrack(List<String> result, List<String> tempList, String s, Set<String> dict, int start) {
        if (start == s.length()) {
            result.add(String.join(" ", tempList));
        }
        for (int i = start; i < s.length(); i++) {
            String sub = s.substring(start, i + 1);
            if (dict.contains(sub)) {
                tempList.add(sub);
                backtrack(result, tempList, s, dict, i + 1);
                tempList.remove(tempList.size() - 1);
            }
        }
    }
}

