def wordBreak(s, wordDict):
    def backtrack(start, path):
        if start == len(s):
            result.append(' '.join(path))
        for end in range(start + 1, len(s) + 1):
            word = s[start:end]
            if word in wordDict:
                backtrack(end, path + [word])
    result = []
    backtrack(0, [])
    return result

