function wordBreak(s, wordDict) {
    let result = [];
    function backtrack(start, path) {
        if (start === s.length) {
            result.push(path.join(' '));
        }
        for (let end = start + 1; end <= s.length; end++) {
            let word = s.slice(start, end);
            if (wordDict.includes(word)) {
                backtrack(end, path.concat([word]));
            }
        }
    }
    backtrack(0, []);
    return result;
}
